with open(r'C:\Users\hp\.gemini\antigravity\scratch\mybbt-tools\templates\reco_tool.html', 'w', encoding='utf-8') as html_file:
    html_file.write('{% extends "base.html" %}\n{% block title %}GST Reco Pro — MYBBT Intelligence Engine{% endblock %}\n{% block page_id %}reco-tool{% endblock %}\n{% block topbar_title %}MYBBT Reco Engine v2.0{% endblock %}\n{% block topbar_breadcrumb %}<span>GST Tools</span> › Reco Engine v2.0{% endblock %}\n\n{% block extra_css %}\n<link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css">\n<style>\n  /* Base Layout */\n  .app-container {\n    display: flex;\n    height: calc(100vh - 70px);\n    background: var(--bg);\n    margin: -20px; /* offset base padding */\n    overflow: hidden;\n  }\n  \n  /* Sidebar */\n  .sidebar {\n    width: 260px;\n    background: #111827;\n    color: #fff;\n    display: flex;\n    flex-direction: column;\n    box-shadow: 2px 0 10px rgba(0,0,0,0.3);\n    z-index: 10;\n  }\n  .sidebar-header {\n    padding: 20px;\n    display: flex;\n    align-items: center;\n    gap: 15px;\n    border-bottom: 1px solid #1f2937;\n  }\n  .sidebar-icon {\n    background: #3b82f6;\n    color: white;\n    width: 40px; height: 40px;\n    border-radius: 8px;\n    display: flex; justify-content: center; align-items: center;\n    font-size: 1.2em;\n    box-shadow: 0 4px 12px rgba(59, 130, 246, 0.4);\n  }\n  .sidebar-title h2 { margin: 0; font-size: 1.2em; font-weight: 700; color: #fff; }\n  .sidebar-title span { font-size: 0.8em; color: #10b981; font-weight: 600; }\n  \n  .nav-menu {\n    flex: 1;\n    overflow-y: auto;\n    padding: 15px 0;\n  }\n  .nav-group {\n    font-size: 0.75em;\n    text-transform: uppercase;\n    letter-spacing: 1px;\n    color: #6b7280;\n    padding: 10px 20px;\n    font-weight: 700;\n  }\n  .nav-item {\n    padding: 12px 20px;\n    cursor: pointer;\n    display: flex;\n    align-items: center;\n    gap: 15px;\n    color: #d1d5db;\n    transition: all 0.2s;\n    border-left: 3px solid transparent;\n  }\n  .nav-item:hover { background: #1f2937; color: #fff; }\n  .nav-item.active {\n    background: #1e3a8a;\n    color: #fff;\n    border-left-color: #3b82f6;\n  }\n  .sidebar-footer {\n    padding: 20px;\n    border-top: 1px solid #1f2937;\n  }\n  \n  /* Main Content Area */\n  .main-content {\n    flex: 1;\n    overflow-y: auto;\n    background: linear-gradient(-45deg, #ee7752, #e73c7e, #23a6d5, #23d5ab);\n    background-size: 400% 400%;\n    animation: gradientBG 15s ease infinite;\n    padding: 30px;\n    position: relative;\n  }\n  @keyframes gradientBG {\n    0% { background-position: 0% 50%; }\n    50% { background-position: 100% 50%; }\n    100% { background-position: 0% 50%; }\n  }\n  \n  .glass-panel {\n    background: rgba(255, 255, 255, 0.9);\n    backdrop-filter: blur(10px);\n    -webkit-backdrop-filter: blur(10px);\n    border: 1px solid rgba(255, 255, 255, 0.4);\n    border-radius: 12px;\n    padding: 30px;\n    box-shadow: 0 8px 32px 0 rgba(31, 38, 135, 0.1);\n    color: #1f2937;\n    margin-bottom: 20px;\n    display: none; /* Hidden by default */\n    animation: fadeIn 0.3s ease;\n  }\n  .glass-panel.active { display: block; }\n  @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }\n  \n  @media (prefers-color-scheme: dark) {\n    body.dark-mode .glass-panel {\n      background: rgba(30, 30, 30, 0.85);\n      border: 1px solid rgba(255, 255, 255, 0.1);\n      color: #eee;\n    }\n  }\n\n  /* Form & Components */\n  .panel-title { font-size: 1.8em; font-weight: 800; margin-bottom: 5px; color: var(--primary); }\n  .panel-subtitle { color: var(--text-muted); margin-bottom: 25px; font-size: 0.95em; }\n  \n  .section-card {\n    background: var(--surface-2);\n    border: 1px solid var(--border);\n    border-radius: 8px;\n    padding: 20px;\n    margin-bottom: 20px;\n  }\n  .section-card-title {\n    font-weight: 700; font-size: 1.1em; margin-bottom: 15px;\n    display: flex; align-items: center; gap: 8px;\n  }\n  \n  .form-control-premium {\n    width: 100%; padding: 10px 15px; border: 1px solid var(--border);\n    border-radius: 6px; background: var(--bg); color: var(--text);\n    transition: all 0.2s;\n  }\n  .form-control-premium:focus { border-color: #3b82f6; box-shadow: 0 0 0 3px rgba(59, 130, 246, 0.2); outline: none; }\n  \n  .upload-box {\n    border: 2px dashed #9ca3af; border-radius: 8px; padding: 25px;\n    text-align: center; background: var(--bg); cursor: pointer; position: relative;\n    transition: all 0.2s;\n  }\n  .upload-box:hover { border-color: #3b82f6; background: rgba(59, 130, 246, 0.05); }\n  .upload-box input[type="file"] { position: absolute; top: 0; left: 0; width: 100%; height: 100%; opacity: 0; cursor: pointer; }\n  \n  .btn-run {\n    width: 100%; background: #3b82f6; color: white; border: none; padding: 12px;\n    border-radius: 6px; font-weight: 600; font-size: 1.1em; cursor: pointer;\n    display: flex; justify-content: center; align-items: center; gap: 10px;\n    transition: background 0.2s;\n  }\n  .btn-run:hover { background: #2563eb; }\n  .btn-run:disabled { background: #9ca3af; cursor: not-allowed; }\n  \n  /* Tables */\n  .rule-table { width: 100%; border-collapse: collapse; font-size: 0.9em; background: var(--bg); border-radius: 6px; overflow: hidden; }\n  .rule-table th, .rule-table td { padding: 10px; border: 1px solid var(--border); text-align: left; }\n  .rule-table th { background: var(--surface-2); font-weight: 600; }\n  .rule-table tr:hover { background: var(--surface-2); }\n  .table-actions { display: flex; gap: 10px; margin-bottom: 15px; }\n  .btn-sm { padding: 5px 12px; font-size: 0.85em; border-radius: 4px; border: 1px solid var(--border); background: var(--surface-2); color: var(--text); cursor: pointer; }\n  .btn-sm:hover { background: var(--border); }\n  .btn-sm.primary { background: #3b82f6; color: white; border-color: #3b82f6; }\n  .btn-sm.primary:hover { background: #2563eb; }\n  \n  /* Toggles */\n  .toggle-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(300px, 1fr)); gap: 15px; }\n  .toggle-card {\n    display: flex; justify-content: space-between; align-items: center;\n    padding: 15px; background: var(--bg); border: 1px solid var(--border); border-radius: 8px;\n  }\n  .toggle-info strong { display: block; margin-bottom: 3px; }\n  .toggle-info small { color: var(--text-muted); font-size: 0.85em; }\n  \n  /* Switch */\n  .switch { position: relative; display: inline-block; width: 44px; height: 24px; }\n  .switch input { opacity: 0; width: 0; height: 0; }\n  .slider { position: absolute; cursor: pointer; top: 0; left: 0; right: 0; bottom: 0; background-color: #ccc; transition: .4s; border-radius: 24px; }\n  .slider:before { position: absolute; content: ""; height: 18px; width: 18px; left: 3px; bottom: 3px; background-color: white; transition: .4s; border-radius: 50%; }\n  input:checked + .slider { background-color: #3b82f6; }\n  input:checked + .slider:before { transform: translateX(20px); }\n  \n  /* Log output */\n  #logOutput {\n    background: #111827; color: #10b981; font-family: monospace; padding: 15px;\n    border-radius: 8px; height: 300px; overflow-y: auto; white-space: pre-wrap; font-size: 0.9em;\n  }\n  \n  /* Progress Bar */\n  .progress-wrapper { background: var(--surface-2); border: 1px solid var(--border); border-radius: 12px; padding: 25px; margin-top: 25px; text-align: center; display: none; }\n  .progress-bar-container { width: 100%; height: 12px; background: var(--border); border-radius: 6px; overflow: hidden; margin: 15px 0; }\n  .progress-bar-fill { height: 100%; background: linear-gradient(90deg, #3b82f6, #10b981); width: 0%; transition: width 0.4s ease; }\n</style>\n{% endblock %}\n\n{% block content %}\n<div class="app-container">\n  \n  <!-- Sidebar -->\n  <div class="sidebar">\n    <div class="sidebar-header">\n      <div class="sidebar-icon"><i class="fa-solid fa-bolt"></i></div>\n      <div class="sidebar-title">\n        <h2>GST Reco</h2>\n        <span>Pro v2.0</span>\n      </div>\n    </div>\n    \n    <div class="nav-menu">\n      <div class="nav-group">Navigation</div>\n      <div class="nav-item active" data-target="panel-reco">\n        <i class="fa-solid fa-house"></i> Reconciliation\n      </div>\n      <div class="nav-item" data-target="panel-match">\n        <i class="fa-solid fa-list-check"></i> Match Rules\n      </div>\n      <div class="nav-item" data-target="panel-ko">\n        <i class="fa-solid fa-scissors"></i> Knockout Rules\n      </div>\n      <div class="nav-item" data-target="panel-features">\n        <i class="fa-solid fa-bolt"></i> Feature Toggles\n      </div>\n      <div class="nav-item" data-target="panel-settings">\n        <i class="fa-solid fa-gear"></i> Settings\n      </div>\n      <div class="nav-item" data-target="panel-log">\n        <i class="fa-solid fa-terminal"></i> Log\n      </div>\n    </div>\n    \n    <div class="sidebar-footer">\n      <button class="btn-run" id="btnRunReco">\n        <i class="fa-solid fa-play"></i> Run Reconciliation\n      </button>\n    </div>\n  </div>\n  \n  <!-- Main Content -->\n  <div class="main-content">\n    \n    <form id="recoForm">\n      \n      <!-- Panel: Reconciliation -->\n      <div id="panel-reco" class="glass-panel active">\n        <div style="display: flex; justify-content: space-between; align-items: center;">\n          <div>\n            <h1 class="panel-title">Reconciliation</h1>\n            <p class="panel-subtitle">PR ↔ GSTR-2B matching engine</p>\n          </div>\n          <div style="display: flex; gap: 10px;">\n            <a href="/api/reco/template?type=pr" class="btn btn-outline-primary btn-sm"><i class="fa-solid fa-download"></i> PR Template</a>\n            <a href="/api/reco/template?type=2b" class="btn btn-outline-primary btn-sm"><i class="fa-solid fa-download"></i> 2B Template</a>\n          </div>\n        </div>\n        \n        <div class="section-card">\n          <div class="section-card-title"><i class="fa-solid fa-user"></i> Client Details</div>\n          <input type="text" name="client_name" class="form-control-premium" placeholder="Client Name (Appears on output sheet)">\n        </div>\n        \n        <div class="section-card">\n          <div class="section-card-title"><i class="fa-solid fa-folder-open"></i> Files</div>\n          <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 20px;">\n            <div class="upload-box" id="pr_box">\n              <strong style="color:var(--primary);">Purchase Register (Excel)</strong><br>\n              <small class="text-muted">Click or Drag file</small>\n              <div id="pr_name" style="margin-top:10px; color:#10b981; font-weight:600;"></div>\n              <input type="file" id="pr_file" name="pr_file" accept=".xlsx,.xls,.csv">\n            </div>\n            <div class="upload-box" id="b2_box">\n              <strong style="color:var(--primary);">GSTR-2B File (Excel)</strong><br>\n              <small class="text-muted">Click or Drag file</small>\n              <div id="b2_name" style="margin-top:10px; color:#10b981; font-weight:600;"></div>\n              <input type="file" id="b2_file" name="b2_file" accept=".xlsx,.xls,.csv">\n            </div>\n          </div>\n        </div>\n        \n        <!-- Progress Container -->\n        <div id="progressContainer" class="progress-wrapper">\n          <h3 style="margin-top: 0; color: var(--primary);" id="progressStatus">Starting Engine...</h3>\n          <div class="progress-bar-container">\n            <div id="progressBar" class="progress-bar-fill"></div>\n          </div>\n          <p id="progressMessage" style="color: var(--text-muted);">Please wait...</p>\n          <p id="etaMessage" style="font-size: 0.85em; font-weight: bold; color: #f59e0b;"></p>\n        </div>\n        \n        <div id="successBox" class="glass-panel" style="background: rgba(16, 185, 129, 0.1); border-color: #10b981; text-align: center; margin-top: 20px;">\n          <h2 style="color: #10b981;">✅ Reconciliation Complete!</h2>\n          <p>Your analysis sheets are ready.</p>\n          <a id="downloadBtn" href="#" class="btn-run" style="background: #10b981; width: auto; display: inline-flex; margin-top: 15px;">\n            <i class="fa-solid fa-download"></i> Download Report\n          </a>\n        </div>\n        \n      </div>\n      \n      <!-- Panel: Match Rules -->\n      <div id="panel-match" class="glass-panel">\n        <h1 class="panel-title">Match Rules</h1>\n        <p class="panel-subtitle">Column combinations for PR ↔ GSTR-2B (top = highest priority)</p>\n        \n        <div class="table-actions">\n          <button type="button" class="btn-sm primary" id="btnRestoreMatchRules"><i class="fa-solid fa-rotate-left"></i> Reset Defaults</button>\n        </div>\n        \n        <div style="overflow-x: auto;">\n          <table class="rule-table" id="matchRulesTable">\n            <thead>\n              <tr>\n                <th width="50">On</th>\n                <th width="200">Label</th>\n                <th>Columns (comma separated)</th>\n                <th width="200">Remark</th>\n              </tr>\n            </thead>\n            <tbody>\n              <!-- JS Populated -->\n            </tbody>\n          </table>\n        </div>\n      </div>\n      \n      <!-- Panel: Knockout Rules -->\n      <div id="panel-ko" class="glass-panel">\n        <h1 class="panel-title">Knockout Rules</h1>\n        <p class="panel-subtitle">Positive+negative pairs that cancel out are removed before matching</p>\n        \n        <div class="table-actions">\n          <button type="button" class="btn-sm primary" id="btnRestoreKORules"><i class="fa-solid fa-rotate-left"></i> Reset Defaults</button>\n        </div>\n        \n        <div style="overflow-x: auto;">\n          <table class="rule-table" id="prkoRulesTable">\n            <thead>\n              <tr>\n                <th width="50">On</th>\n                <th width="200">Label</th>\n                <th>Columns (comma separated)</th>\n                <th width="100">Tax Head</th>\n                <th width="80">Max</th>\n              </tr>\n            </thead>\n            <tbody>\n              <!-- JS Populated -->\n            </tbody>\n          </table>\n        </div>\n      </div>\n      \n      <!-- Panel: Feature Toggles -->\n      <div id="panel-features" class="glass-panel">\n        <h1 class="panel-title">Feature Toggles</h1>\n        <p class="panel-subtitle">Switch individual matching steps on or off</p>\n        \n        <div class="toggle-grid">\n          <div class="toggle-card">\n            <div class="toggle-info">\n              <strong>User Knock-Off</strong>\n              <small>Skip rows marked YES in Is Bank / Knock Off col</small>\n            </div>\n            <label class="switch"><input type="checkbox" name="user_knockoff" value="true" checked><span class="slider"></span></label>\n          </div>\n          <div class="toggle-card">\n            <div class="toggle-info">\n              <strong>PR Internal Knockout</strong>\n              <small>Find +/- pairs in PR that cancel</small>\n            </div>\n            <label class="switch"><input type="checkbox" name="pr_knockout" value="true" checked><span class="slider"></span></label>\n          </div>\n          <div class="toggle-card">\n            <div class="toggle-info">\n              <strong>2B Internal Knockout</strong>\n              <small>Find +/- pairs in 2B that cancel</small>\n            </div>\n            <label class="switch"><input type="checkbox" name="2b_knockout" value="true" checked><span class="slider"></span></label>\n          </div>\n          <div class="toggle-card">\n            <div class="toggle-info">\n              <strong>Rule-Based Match</strong>\n              <small>Exact matching based on Match Rules</small>\n            </div>\n            <label class="switch"><input type="checkbox" name="rule_match" value="true" checked><span class="slider"></span></label>\n          </div>\n          <div class="toggle-card">\n            <div class="toggle-info">\n              <strong>Fuzzy Invoice Logic</strong>\n              <small>Normalize strings, strip zeros for match</small>\n            </div>\n            <label class="switch"><input type="checkbox" name="fuzzy_invoice" value="true" checked><span class="slider"></span></label>\n          </div>\n          <div class="toggle-card">\n            <div class="toggle-info">\n              <strong>Month/Year Match</strong>\n              <small>Match by aggregate month values</small>\n            </div>\n            <label class="switch"><input type="checkbox" name="month_year_match" value="true" checked><span class="slider"></span></label>\n          </div>\n          <div class="toggle-card">\n            <div class="toggle-info">\n              <strong>Bank MAX Match (v2)</strong>\n              <small>Advanced subset sum for bank aggregates</small>\n            </div>\n            <label class="switch"><input type="checkbox" name="bank_max_match" value="true" checked><span class="slider"></span></label>\n          </div>\n        </div>\n      </div>\n      \n      <!-- Panel: Settings -->\n      <div id="panel-settings" class="glass-panel">\n        <h1 class="panel-title">Settings</h1>\n        <p class="panel-subtitle">Configure tolerances and output delivery</p>\n        \n        <div class="section-card">\n          <div class="section-card-title"><i class="fa-solid fa-sliders"></i> Global Tolerances</div>\n          <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 15px;">\n            <div>\n              <label style="font-size:0.9em; font-weight:600;">Amount Tolerance (₹)</label>\n              <input type="number" name="amount_tolerance" value="10" step="0.01" class="form-control-premium">\n            </div>\n            <div>\n              <label style="font-size:0.9em; font-weight:600;">Percentage Tolerance (%)</label>\n              <input type="number" name="pct_tolerance" value="5" step="0.1" class="form-control-premium">\n            </div>\n          </div>\n        </div>\n        \n        <div class="section-card">\n          <div class="section-card-title">\n            <i class="fa-solid fa-envelope"></i> Email Delivery\n            <label class="switch" style="margin-left:auto;"><input type="checkbox" id="email_enabled" name="email_enabled" value="true"><span class="slider"></span></label>\n          </div>\n          <div id="emailConfig" style="display:none; margin-top: 15px;">\n            <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 15px; margin-bottom: 15px;">\n              <div>\n                <label style="font-size:0.9em; font-weight:600;">Send To Email</label>\n                <input type="email" name="email_to" class="form-control-premium" placeholder="client@example.com">\n              </div>\n              <div>\n                <label style="font-size:0.9em; font-weight:600;">SMTP Host</label>\n                <input type="text" name="smtp_host" class="form-control-premium" value="smtp.gmail.com">\n              </div>\n            </div>\n            <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 15px;">\n              <div>\n                <label style="font-size:0.9em; font-weight:600;">SMTP User (Your Email)</label>\n                <input type="email" name="smtp_user" class="form-control-premium" placeholder="you@gmail.com">\n              </div>\n              <div>\n                <label style="font-size:0.9em; font-weight:600;">SMTP App Password</label>\n                <input type="password" name="smtp_pass" class="form-control-premium" placeholder="16-digit app password">\n              </div>\n            </div>\n          </div>\n        </div>\n      </div>\n      \n      <!-- Panel: Log -->\n      <div id="panel-log" class="glass-panel">\n        <h1 class="panel-title">Console Log</h1>\n        <p class="panel-subtitle">Real-time output from the matching engine</p>\n        <div id="logOutput">Logs will appear here once reconciliation starts...</div>\n      </div>\n      \n    </form>\n  </div>\n</div>\n{% endblock %}\n\n{% block extra_js %}\n<script>\n  // -- Navigation Logic --\n  document.querySelectorAll(\'.nav-item\').forEach(item => {\n    item.addEventListener(\'click\', function() {\n      document.querySelectorAll(\'.nav-item\').forEach(n => n.classList.remove(\'active\'));\n      document.querySelectorAll(\'.glass-panel\').forEach(p => p.classList.remove(\'active\'));\n      \n      this.classList.add(\'active\');\n      document.getElementById(this.dataset.target).classList.add(\'active\');\n    });\n  });\n  \n  // -- File Input Display --\n  document.getElementById(\'pr_file\').addEventListener(\'change\', function() {\n    if(this.files[0]) document.getElementById(\'pr_name\').style.display = \'block\';\n    document.getElementById(\'pr_name\').textContent = this.files[0] ? this.files[0].name : \'\';\n  });\n  document.getElementById(\'b2_file\').addEventListener(\'change\', function() {\n    if(this.files[0]) document.getElementById(\'b2_name\').style.display = \'block\';\n    document.getElementById(\'b2_name\').textContent = this.files[0] ? this.files[0].name : \'\';\n  });\n  \n  // -- Email Toggle --\n  document.getElementById(\'email_enabled\').addEventListener(\'change\', function() {\n    document.getElementById(\'emailConfig\').style.display = this.checked ? \'block\' : \'none\';\n  });\n\n  // -- Default Rules Configuration --\n  const DEFAULT_MATCH_RULES = [\n    {enabled: true, label: "GSTIN+Invoice+Date+Tax", cols: "GSTIN,Invoice Number,Invoice Date,Total Tax", remark: "Perfect Match"},\n    {enabled: true, label: "GSTIN+Invoice+Tax", cols: "GSTIN,Invoice Number,Total Tax", remark: "Match - Date differs"},\n    {enabled: true, label: "GSTIN+Invoice+Date", cols: "GSTIN,Invoice Number,Invoice Date", remark: "Match - Tax differs"},\n    {enabled: true, label: "GSTIN+Invoice", cols: "GSTIN,Invoice Number", remark: "Match - Tax & Date differ"},\n    {enabled: true, label: "PAN+Invoice+Date+Tax", cols: "Pan,Invoice Number,Invoice Date,Total Tax", remark: "PAN Match - GSTIN differs"},\n    {enabled: true, label: "PAN+Invoice+Tax", cols: "Pan,Invoice Number,Total Tax", remark: "PAN Match - Date differs"},\n    {enabled: true, label: "PAN+Invoice+Date", cols: "Pan,Invoice Number,Invoice Date", remark: "PAN Match - Tax differs"},\n    {enabled: true, label: "PAN+Invoice", cols: "Pan,Invoice Number", remark: "PAN Match - Tax & Date differ"},\n    {enabled: true, label: "Invoice+Tax", cols: "Invoice Number,Total Tax", remark: "Match - GSTIN/PAN mismatch"},\n    {enabled: true, label: "GSTIN+RoundedTax", cols: "GSTIN,Total Tax Round", remark: "Rounding Difference Match"},\n    {enabled: true, label: "GSTIN+MonthYear+Tax", cols: "GSTIN,Month Year,Total Tax", remark: "Month-Year Match"}\n  ];\n  \n  const DEFAULT_PR_KO = [\n    {enabled: true, label: "PAN+Invoice+State", cols: "Pan,Invoice Number,State", tax_head: true, max: 3},\n    {enabled: true, label: "PAN+Invoice", cols: "Pan,Invoice Number", tax_head: true, max: 3},\n    {enabled: true, label: "GSTIN+Invoice", cols: "GSTIN,Invoice Number", tax_head: true, max: 3},\n    {enabled: true, label: "PAN+State", cols: "Pan,State", tax_head: true, max: 2}\n  ];\n  \n  // -- Rule Rendering --\n  function loadRules() {\n    let matchRules = JSON.parse(localStorage.getItem(\'mybbt_match_rules\')) || DEFAULT_MATCH_RULES;\n    let koRules = JSON.parse(localStorage.getItem(\'mybbt_pr_ko_rules\')) || DEFAULT_PR_KO;\n    \n    renderTable(\'matchRulesTable\', matchRules, false);\n    renderTable(\'prkoRulesTable\', koRules, true);\n  }\n  \n  function saveRules() {\n    let matchRules = extractRules(\'matchRulesTable\', false);\n    let koRules = extractRules(\'prkoRulesTable\', true);\n    localStorage.setItem(\'mybbt_match_rules\', JSON.stringify(matchRules));\n    localStorage.setItem(\'mybbt_pr_ko_rules\', JSON.stringify(koRules));\n  }\n  \n  function extractRules(tableId, isKO) {\n    let rules = [];\n    document.querySelectorAll(`#${tableId} tbody tr`).forEach(row => {\n      let inputs = row.querySelectorAll(\'input\');\n      if(!isKO) {\n        rules.push({\n          enabled: inputs[0].checked,\n          label: inputs[1].value,\n          cols: inputs[2].value.split(\',\').map(s=>s.trim()).filter(s=>s),\n          remark: inputs[3].value\n        });\n      } else {\n        rules.push({\n          enabled: inputs[0].checked,\n          label: inputs[1].value,\n          cols: inputs[2].value.split(\',\').map(s=>s.trim()).filter(s=>s),\n          tax_head: inputs[3].checked,\n          max: parseInt(inputs[4].value)\n        });\n      }\n    });\n    return rules;\n  }\n  \n  function renderTable(tableId, rules, isKO) {\n    let tbody = document.querySelector(`#${tableId} tbody`);\n    tbody.innerHTML = \'\';\n    rules.forEach((r, i) => {\n      let tr = document.createElement(\'tr\');\n      let colsStr = Array.isArray(r.cols) ? r.cols.join(\',\') : r.cols;\n      if(!isKO) {\n        tr.innerHTML = `\n          <td style="text-align:center;"><input type="checkbox" onchange="saveRules()" ${r.enabled?\'checked\':\'\'}></td>\n          <td><input type="text" class="form-control-premium" style="padding:5px;" value="${r.label}" onchange="saveRules()"></td>\n          <td><input type="text" class="form-control-premium" style="padding:5px;" value="${colsStr}" onchange="saveRules()"></td>\n          <td><input type="text" class="form-control-premium" style="padding:5px;" value="${r.remark||\'\'}" onchange="saveRules()"></td>\n        `;\n      } else {\n        tr.innerHTML = `\n          <td style="text-align:center;"><input type="checkbox" onchange="saveRules()" ${r.enabled?\'checked\':\'\'}></td>\n          <td><input type="text" class="form-control-premium" style="padding:5px;" value="${r.label}" onchange="saveRules()"></td>\n          <td><input type="text" class="form-control-premium" style="padding:5px;" value="${colsStr}" onchange="saveRules()"></td>\n          <td style="text-align:center;"><input type="checkbox" onchange="saveRules()" ${r.tax_head?\'checked\':\'\'}></td>\n          <td><input type="number" class="form-control-premium" style="padding:5px;" value="${r.max||3}" onchange="saveRules()"></td>\n        `;\n      }\n      tbody.appendChild(tr);\n    });\n  }\n  \n  document.getElementById(\'btnRestoreMatchRules\').addEventListener(\'click\', () => { renderTable(\'matchRulesTable\', DEFAULT_MATCH_RULES, false); saveRules(); });\n  document.getElementById(\'btnRestoreKORules\').addEventListener(\'click\', () => { renderTable(\'prkoRulesTable\', DEFAULT_PR_KO, true); saveRules(); });\n  \n  loadRules();\n  \n  // -- Engine Execution --\n  let pollInterval;\n  document.getElementById(\'btnRunReco\').addEventListener(\'click\', function(e) {\n    e.preventDefault();\n    saveRules(); // ensure latest saved\n    \n    const form = document.getElementById(\'recoForm\');\n    const formData = new FormData(form);\n    \n    // Inject Custom Rules\n    formData.append("match_rules", localStorage.getItem(\'mybbt_match_rules\'));\n    formData.append("pr_ko_rules", localStorage.getItem(\'mybbt_pr_ko_rules\'));\n    formData.append("b2_ko_rules", localStorage.getItem(\'mybbt_pr_ko_rules\')); // Using PR KO logic for 2B KO for symmetry as per v116\n    \n    const prFile = document.getElementById(\'pr_file\').files[0];\n    const b2File = document.getElementById(\'b2_file\').files[0];\n    \n    if (!prFile && !b2File) {\n      alert("Please upload at least PR or 2B file.");\n      document.querySelector(\'.nav-item[data-target="panel-reco"]\').click();\n      return;\n    }\n    \n    this.disabled = true;\n    this.innerHTML = \'<i class="fa-solid fa-spinner fa-spin"></i> Initializing Engine...\';\n    \n    // Switch to Reco tab\n    document.querySelector(\'.nav-item[data-target="panel-reco"]\').click();\n    \n    document.getElementById(\'progressContainer\').style.display = \'block\';\n    document.getElementById(\'successBox\').style.display = \'none\';\n    document.getElementById(\'logOutput\').innerHTML = \'Engine triggered...\\n\';\n    \n    fetch(\'/api/reco/run\', { method: \'POST\', body: formData })\n      .then(res => res.json())\n      .then(data => {\n        if (!data.success) throw new Error(data.error);\n        pollStatus(data.task_id);\n      })\n      .catch(err => {\n        alert("Error: " + err.message);\n        resetBtn();\n      });\n  });\n  \n  function pollStatus(taskId) {\n    pollInterval = setInterval(() => {\n      fetch(\'/api/reco/status/\' + taskId)\n        .then(res => res.json())\n        .then(data => {\n          if (data.status === \'processing\') {\n            document.getElementById(\'progressStatus\').innerText = "Processing...";\n            if (data.message) {\n              document.getElementById(\'progressMessage\').innerText = data.message;\n              document.getElementById(\'logOutput\').innerHTML += data.message + \'\\n\';\n              document.getElementById(\'logOutput\').scrollTop = document.getElementById(\'logOutput\').scrollHeight;\n            }\n            if (data.percent !== undefined) document.getElementById(\'progressBar\').style.width = data.percent + \'%\';\n            if (data.eta > 0) document.getElementById(\'etaMessage\').innerText = `ETA: ${data.eta} sec`;\n            \n          } else if (data.status === \'done\') {\n            clearInterval(pollInterval);\n            document.getElementById(\'progressContainer\').style.display = \'none\';\n            document.getElementById(\'successBox\').style.display = \'block\';\n            document.getElementById(\'downloadBtn\').href = \'/api/reco/download/\' + taskId;\n            document.getElementById(\'logOutput\').innerHTML += \'\\n✅ Finished successfully!\\n\';\n            resetBtn();\n            \n          } else if (data.status === \'error\') {\n            clearInterval(pollInterval);\n            document.getElementById(\'progressContainer\').style.display = \'none\';\n            document.getElementById(\'logOutput\').innerHTML += \'\\n❌ Error: \' + data.message + \'\\n\';\n            alert("Error: " + data.message);\n            resetBtn();\n          }\n        });\n    }, 1000);\n  }\n  \n  function resetBtn() {\n    let btn = document.getElementById(\'btnRunReco\');\n    btn.disabled = false;\n    btn.innerHTML = \'<i class="fa-solid fa-play"></i> Run Reconciliation\';\n  }\n</script>\n{% endblock %}')